      out.write("function setPlantState(strPlant,holiday_state_map)\r\n");
      out.write("{\r\n");
      out.write("	var chk_plant = document.forms[0].chk_plant;\r\n");
      out.write("	var holiday_state = document.forms[0].holiday_state;\r\n");
      out.write("	var plant_seq = strPlant.split(\"@\");\r\n");
      out.write("	\r\n");
      out.write("	var split_state_map = holiday_state_map.split(\"@@\");   2//01@02@03;   3//01@02@03\r\n");
      out.write("	var stateCd;\r\n");
      out.write("	var plantCd;\r\n");
      out.write("	var stateMap;\r\n");
      out.write("	for(var k=0; k<split_state_map.length; k++)\r\n");
      out.write("	{\r\n");
      out.write("		plantCd = split_state_map[k].split(\"//\")[0];\r\n");
      out.write("		stateMap = split_state_map[k].split(\"//\")[1];\r\n");
      out.write("		\r\n");
      out.write("		if(chk_plant!=null && chk_plant.length!=undefined)\r\n");
      out.write("	 	{\r\n");
      out.write("	  		for(var i=0;i<chk_plant.length;i++)\r\n");
      out.write("	  		{\r\n");
      out.write("	   			for(var j=0;j<plant_seq.length;j++)\r\n");
      out.write("	   			{\r\n");
      out.write("	     			if(chk_plant[i].value == plant_seq[j])\r\n");
      out.write("	     			{\r\n");
      out.write("	     				chk_plant[i].checked = true;\r\n");
      out.write("	     				\r\n");
      out.write("	     				if(plantCd===plant_seq[j])\r\n");
      out.write("	     				{\r\n");
      out.write("	     					stateCd = stateMap.split(\"@\");\r\n");
      out.write("	     					\r\n");
      out.write("	     					for(var l=0; l<stateCd.length; l++)\r\n");
      out.write("	     					{\r\n");
      out.write("	     						var dropdown = document.getElementById('holiday_state_'+i);\r\n");
      out.write("	     						\r\n");
      out.write("	     						for (let m = 0; m < dropdown.options.length; m++) \r\n");
      out.write("	     						{\r\n");
      out.write("	     							if (dropdown.options[m].value === stateCd[l]) \r\n");
      out.write("	     							{\r\n");
      out.write("	     								dropdown.options[m].selected=true;\r\n");
      out.write("	     							}\r\n");
      out.write("	     						}\r\n");
      out.write("	     					}\r\n");
      out.write("	     				}\r\n");
      out.write("	     			}\r\n");
      out.write("	   			} \r\n");
      out.write("	  		} \r\n");
      out.write("	 	}\r\n");
      out.write("	 	else if(chk_plant!=null)\r\n");
      out.write("	 	{\r\n");
      out.write("	   		for(var j=0;j<plant_seq.length;j++)\r\n");
      out.write("	   		{\r\n");
      out.write("	   			if(chk_plant.value == plant_seq[j])\r\n");
      out.write("	     		{\r\n");
      out.write("	   				chk_plant.checked = true;\r\n");
      out.write("	   				if(plantCd===plant_seq[j])\r\n");
      out.write("     				{\r\n");
      out.write("     					stateCd = stateMap.split(\"@\");\r\n");
      out.write("     					\r\n");
      out.write("     					for(var l=0; l<stateCd.length; l++)\r\n");
      out.write("     					{\r\n");
      out.write("     						var dropdown = document.getElementById('holiday_state_0');\r\n");
      out.write("     						\r\n");
      out.write("     						for (let m = 0; m < dropdown.options.length; m++) \r\n");
